import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

export default function Topbar() {
    const navigate = useNavigate();
    const [showMenu, setShowMenu] = useState(false);

    const logout = () => {
        localStorage.clear();
        navigate("/login");
    };

    return (
        <div className="topbar">
            {/* Search Bar (Mock) */}
            <div className="topbar-search">
                <i className="fa-solid fa-magnifying-glass"></i>
                <input type="text" placeholder="Search locations, bookings..." style={{ height: '30px' }} />
            </div>

            {/* Right Actions */}
            <div className="topbar-actions">
                <div className="notification-bell" onClick={() => alert("No new notifications")}>
                    <i className="fa-regular fa-bell"></i>
                    <div className="notification-dot"></div>
                </div>

                <div style={{ position: 'relative' }}>
                    <div className="user-profile-menu" onClick={() => setShowMenu(!showMenu)}>
                        <div className="user-avatar">
                            {localStorage.getItem('role') === 'admin' ? 'A' : 'U'}
                        </div>
                        <i className="fa-solid fa-chevron-down" style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}></i>
                    </div>

                    {/* Dropdown Menu */}
                    {showMenu && (
                        <div style={{ position: 'absolute', top: '100%', right: 0, marginTop: '8px', background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)', boxShadow: 'var(--shadow-lg)', borderRadius: 'var(--radius-sm)', width: '200px', zIndex: 100, animation: 'fadeIn 0.2s', overflow: 'hidden' }}>
                            <div style={{ padding: '16px', borderBottom: '1px solid var(--border-subtle)' }}>
                                <div style={{ fontWeight: 'bold', color: 'var(--text-primary)' }}>Account</div>
                                <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>{localStorage.getItem('role') === 'admin' ? 'Admin Access' : 'User Access'}</div>
                            </div>
                            <div style={{ padding: '8px' }}>
                                <button className="dropdown-item" onClick={() => { setShowMenu(false); alert("Profile modal opening..."); }} style={dropdownBtnStyle}>
                                    <i className="fa-regular fa-user" style={{ width: '20px' }}></i> Profile
                                </button>
                                <button className="dropdown-item" onClick={() => { setShowMenu(false); alert("Settings opening..."); }} style={dropdownBtnStyle}>
                                    <i className="fa-solid fa-gear" style={{ width: '20px' }}></i> Settings
                                </button>
                            </div>
                            <div style={{ padding: '8px', borderTop: '1px solid var(--border-subtle)' }}>
                                <button className="dropdown-item" onClick={logout} style={{ ...dropdownBtnStyle, color: 'var(--status-danger)' }}>
                                    <i className="fa-solid fa-arrow-right-from-bracket" style={{ width: '20px' }}></i> Logout
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

const dropdownBtnStyle = {
    width: '100%',
    padding: '10px 16px',
    background: 'none',
    border: 'none',
    textAlign: 'left',
    fontSize: '0.95rem',
    cursor: 'pointer',
    color: 'var(--text-secondary)',
    borderRadius: '6px',
    display: 'flex',
    alignItems: 'center',
    transition: 'background 0.2s, color 0.2s'
};
